#include <verilated.h>
#include <iostream>
#include "Vdesign.h"  // Generated by Verilator from your module name

double sc_time_stamp() {
    return 0;
}

int main(int argc, char** argv) {
    // 1. Initialize Verilator context
    Verilated::commandArgs(argc, argv);
    Vdesign* top = new Vdesign;

    int sim_time = 0;

    // 2. Define the test combinations (simulating your #10 delays)
    bool test_a[] = {0, 1, 0, 1};
    bool test_b[] = {0, 0, 1, 1};

    std::cout << "Starting Simulation..." << std::endl;

    for (int i = 0; i < 4; i++) {
        // Apply inputs
        top->in_a = test_a[i];
        top->in_b = test_b[i];

        // Evaluate the circuit logic
        top->eval();

        // Print state (Acts exactly like your $monitor statement)
        std::cout << "Time = " << sim_time << "ns | "
                  << "a = " << (int)top->in_a << ", "
                  << "b = " << (int)top->in_b << " | "
                  << "out = " << (int)top->out << std::endl;

        sim_time += 10; // Advance time step
    }

    // 3. Clean up memory
    top->final();
    delete top;
    return 0;
}
